+import webpack from './helpers/compiler';
+
+describe('Loader', () => {
+  test('Defaults', async () => {
+    const config = {
+      loader: {
+        test: /(png|jpg|svg)/,
+        options: {},
+      },
+    };
+
+    const stats = await webpack('fixture.js', config);
+    const { source } = stats.toJson().modules[1];
+
+    expect(source).toMatchSnapshot();
   });
 });

diff --git a/test/options/context.test.js b/test/options/context.test.js
new file mode 100644
index 0000000..dede935
--- /dev/null
+++ b/test/options/context.test.js
@@ -0,0 +1,24 @@
+/* eslint-disable
+  prefer-destructuring,
+*/
+import webpack from '../helpers/compiler';
+
+describe('Options', () => {
+  describe('context', () => {
+    test('{String}', async () => {
+      const config = {
+        loader: {
+          test: /(png|jpg|svg)/,
+          options: {
+            context: `${__dirname}`,
+          },
+        },
+      };
+
+      const stats = await webpack('fixture.js', config);
+      const { source } = stats.toJson().modules[1];
+
+      expect(source).toMatchSnapshot();
+    });
+  });
+});

diff --git a/test/options/emitFile.test.js b/test/options/emitFile.test.js
new file mode 100644
index 0000000..2915e85
--- /dev/null
+++ b/test/options/emitFile.test.js
@@ -0,0 +1,42 @@
+/* eslint-disable
+  prefer-destructuring,
+*/
+import webpack from '../helpers/compiler';
+
+describe('Options', () => {
+  describe('emitFile', () => {
+    describe('{Boolean}', () => {
+      test('True (Default)', async () => {
+        const config = {
+          loader: {
+            test: /(png|jpg|svg)/,
+            options: {
+              emitFile: true,
+            },
+          },
+        };
+
+        const stats = await webpack('emitFile/fixture.js', config);
+        const { assets } = stats.toJson().modules[1];
+
+        expect(assets[0]).toMatchSnapshot();
+      });
+
+      test('False', async () => {
+        const config = {
+          loader: {
+            test: /(png|jpg|svg)/,
+            options: {
+              emitFile: false,
+            },
+          },
+        };
+
+        const stats = await webpack('emitFile/fixture.js', config);
+        const { assets } = stats.toJson().modules[1];
+
+        expect(assets[0]).toBe(undefined);
+      });
+    });
+  });
+});

diff --git a/test/options/name.test.js b/test/options/name.test.js
new file mode 100644
index 0000000..89022e0
--- /dev/null
+++ b/test/options/name.test.js
@@ -0,0 +1,42 @@
+/* eslint-disable
+  prefer-destructuring,
+*/
+import webpack from '../helpers/compiler';
+
+describe('Options', () => {
+  describe('name', () => {
+    test('{String}', async () => {
+      const config = {
+        loader: {
+          test: /(png|jpg|svg)/,
+          options: {
+            name: '[hash].[ext]',
+          },
+        },
+      };
+
+      const stats = await webpack('fixture.js', config);
+      const { source } = stats.toJson().modules[1];
+
+      expect(source).toMatchSnapshot();
+    });
+
+    test('{Function}', async () => {
+      const config = {
+        loader: {
+          test: /(png|jpg|svg)/,
+          options: {
+            name() {
+              return '[hash].[ext]';
+            },
+          },
+        },
+      };
+
+      const stats = await webpack('fixture.js', config);
+      const { source } = stats.toJson().modules[1];
+
+      expect(source).toMatchSnapshot();
+    });
+  });
+});

diff --git a/test/options/outputPath.test.js b/test/options/outputPath.test.js
new file mode 100644
index 0000000..e58fc83
--- /dev/null
+++ b/test/options/outputPath.test.js
@@ -0,0 +1,42 @@
+/* eslint-disable
+  prefer-destructuring,
+*/
+import webpack from '../helpers/compiler';
+
+describe('Options', () => {
+  describe('outputPath', () => {
+    test('{String}', async () => {
+      const config = {
+        loader: {
+          test: /(png|jpg|svg)/,
+          options: {
+            outputPath: '/test/',
+          },
+        },
+      };
+
+      const stats = await webpack('fixture.js', config);
+      const { source } = stats.toJson().modules[1];
+
+      expect(source).toMatchSnapshot();
+    });
+
+    test('{Function}', async () => {
+      const config = {
+        loader: {
+          test: /(png|jpg|svg)/,
+          options: {
+            outputPath(url) {
+              return `test/${url}`;
+            },
+          },
+        },
+      };
+
+      const stats = await webpack('fixture.js', config);
+      const { source } = stats.toJson().modules[1];
+
+      expect(source).toMatchSnapshot();
+    });
+  });
+});

