+++ b/test/options/emitFile.test.js
@@ -0,0 +1,42 @@
+/* eslint-disable
+  prefer-destructuring,
+*/
+import webpack from '../helpers/compiler';
+
+describe('Options', () => {
+  describe('emitFile', () => {
+    describe('{Boolean}', () => {
+      test('True (Default)', async () => {
+        const config = {
+          loader: {
+            test: /(png|jpg|svg)/,
+            options: {
+              emitFile: true,
+            },
+          },
+        };
+
+        const stats = await webpack('emitFile/fixture.js', config);
+        const { assets } = stats.toJson().modules[1];
+
+        expect(assets[0]).toMatchSnapshot();
+      });
+
+      test('False', async () => {
+        const config = {
+          loader: {
+            test: /(png|jpg|svg)/,
+            options: {
+              emitFile: false,
+            },
+          },
+        };
+
+        const stats = await webpack('emitFile/fixture.js', config);
+        const { assets } = stats.toJson().modules[1];
+
+        expect(assets[0]).toBe(undefined);
+      });
+    });
